"use client";

import * as React from "react";

import { cn } from "@/lib/utils";
import { useExperienceViewport, useHydrated, usePrefersReducedMotion } from "@/components/experience/experience-runtime";

export type RevealVariant = "fade" | "rise" | "blur" | "clip" | "zoom";

const revealCss = `
[data-reveal-item] { transition: opacity var(--reveal-duration, 700ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), transform var(--reveal-duration, 700ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), filter var(--reveal-duration, 700ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), clip-path var(--reveal-duration, 700ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
[data-reveal-stagger]:not([data-revealed]) [data-reveal-item][data-reveal-variant="fade"] { opacity: 0; }
[data-reveal-stagger]:not([data-revealed]) [data-reveal-item][data-reveal-variant="rise"] { opacity: 0; transform: translate3d(0, var(--reveal-distance, 28px), 0); }
[data-reveal-stagger]:not([data-revealed]) [data-reveal-item][data-reveal-variant="blur"] { opacity: 0; filter: blur(12px); }
[data-reveal-stagger]:not([data-revealed]) [data-reveal-item][data-reveal-variant="clip"] { clip-path: inset(0 0 100% 0); }
[data-reveal-stagger]:not([data-revealed]) [data-reveal-item][data-reveal-variant="zoom"] { opacity: 0; transform: scale(.94); }
`;

type RevealContextValue = {
  staggerMs: number;
  variant: RevealVariant;
};

const RevealContext = React.createContext<RevealContextValue | null>(null);

/** Observes the element and reports when it should be revealed (and un-revealed when `once` is false). */
function useRevealTrigger(target: React.RefObject<HTMLElement | null>, enabled: boolean, once: boolean, threshold: number) {
  const [revealed, setRevealed] = React.useState(false);
  React.useEffect(() => {
    const element = target.current;
    if (!element || !enabled) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry?.isIntersecting) {
          setRevealed(true);
          if (once) observer.disconnect();
        } else if (!once) {
          setRevealed(false);
        }
      },
      { threshold, rootMargin: "0px 0px -8% 0px" },
    );
    observer.observe(element);
    return () => observer.disconnect();
  }, [enabled, once, target, threshold]);
  return revealed;
}

export type RevealStaggerProps = React.ComponentProps<"div"> & {
  children: React.ReactNode;
  /** Default variant for every item in the group. */
  variant?: RevealVariant;
  /** Delay between consecutive items in milliseconds. */
  staggerMs?: number;
  durationMs?: number;
  /** Rise travel in pixels. */
  distance?: number;
  easing?: string;
  /** Reveal only the first time the group enters the viewport. */
  once?: boolean;
  /** Fraction of the group that must be visible before revealing. */
  threshold?: number;
};

/**
 * Viewport-entry choreography: descendants wrapped in `RevealItem` (or a
 * `RevealText`) animate in with a shared stagger once the group scrolls into
 * view. The choreography is pure CSS — the group toggles `data-revealed` and
 * assigns per-item delays from DOM order. Server markup and reduced motion
 * render everything in its final state, so content never depends on
 * JavaScript to be readable.
 */
export function RevealStagger({
  children,
  className,
  distance = 28,
  durationMs = 700,
  easing = "cubic-bezier(.22,.61,.21,1)",
  once = true,
  staggerMs = 90,
  style,
  threshold = 0.2,
  variant = "rise",
  ...props
}: RevealStaggerProps) {
  const rootRef = React.useRef<HTMLDivElement>(null);
  const hydrated = useHydrated();
  const reducedMotion = usePrefersReducedMotion();
  const viewport = useExperienceViewport();
  const activeStaggerMs = staggerMs * (viewport === "mobile" ? 0.72 : viewport === "tablet" ? 0.86 : 1);
  const activeDurationMs = durationMs * (viewport === "mobile" ? 0.82 : viewport === "tablet" ? 0.92 : 1);
  const activeDistance = distance * (viewport === "mobile" ? 0.62 : viewport === "tablet" ? 0.8 : 1);
  const activeThreshold = Math.min(threshold, viewport === "mobile" ? 0.12 : viewport === "tablet" ? 0.16 : threshold);
  const animated = hydrated && !reducedMotion;
  const revealed = useRevealTrigger(rootRef, animated, once, activeThreshold);
  const childCount = React.Children.count(children);

  // Stagger delays follow DOM order; items with an explicit order/delay opt out.
  React.useEffect(() => {
    const root = rootRef.current;
    if (!root || !animated) return;
    const items = root.querySelectorAll<HTMLElement>("[data-reveal-item]:not([data-reveal-fixed])");
    items.forEach((item, index) => item.style.setProperty("--reveal-delay", `${index * activeStaggerMs}ms`));
  }, [activeStaggerMs, animated, childCount]);

  const value = React.useMemo<RevealContextValue>(() => ({ staggerMs: activeStaggerMs, variant }), [activeStaggerMs, variant]);

  return (
    <RevealContext.Provider value={value}>
      <style href="reveal-stagger" precedence="medium">{revealCss}</style>
      <div
        ref={rootRef}
        data-reveal-stagger
        data-experience-viewport={viewport}
        data-revealed={(revealed || !animated) || undefined}
        className={className}
        style={{
          "--reveal-duration": `${activeDurationMs}ms`,
          "--reveal-easing": easing,
          "--reveal-distance": `${activeDistance}px`,
          ...style,
        } as React.CSSProperties}
        {...props}
      >
        {children}
      </div>
    </RevealContext.Provider>
  );
}

export type RevealItemProps = React.ComponentProps<"div"> & {
  children: React.ReactNode;
  /** Overrides the group variant for this item. */
  variant?: RevealVariant;
  /**
   * Absolute delay override in milliseconds. Combined with `order`
   * (`order * staggerMs + delayMs`); items using either leave the automatic
   * DOM-order stagger.
   */
  delayMs?: number;
  /** Explicit stagger position; see `delayMs`. */
  order?: number;
};

/**
 * One choreographed element inside a `RevealStagger`. DOM order defines the
 * stagger position unless `order`/`delayMs` pin an explicit delay.
 */
export function RevealItem({ children, className, delayMs, order, style, variant, ...props }: RevealItemProps) {
  const context = React.useContext(RevealContext);
  if (!context) throw new Error("RevealItem must be rendered inside a RevealStagger.");
  const fixed = order !== undefined || delayMs !== undefined;
  const fixedDelay = fixed ? (order ?? 0) * context.staggerMs + (delayMs ?? 0) : undefined;
  return (
    <div
      data-reveal-item
      data-reveal-variant={variant ?? context.variant}
      data-reveal-fixed={fixed || undefined}
      className={className}
      style={fixed ? ({ "--reveal-delay": `${fixedDelay}ms`, ...style } as React.CSSProperties) : style}
      {...props}
    >
      {children}
    </div>
  );
}

export type RevealTextProps = Omit<React.ComponentProps<"span">, "children"> & {
  text: string;
  /** Split unit for the choreography. */
  by?: "word" | "character";
  /** Delay between consecutive units in milliseconds. */
  staggerMs?: number;
  durationMs?: number;
  distance?: string;
  easing?: string;
  once?: boolean;
  threshold?: number;
  /** Class applied to every animated unit (e.g. gradient text per word). */
  unitClassName?: string;
};

/**
 * Masked-line text reveal: the string splits into words or characters that
 * rise out of an `overflow:hidden` mask with a stagger. The full string stays
 * available to assistive tech; the animated fragments are decorative. Works
 * standalone or inside a `RevealStagger` (it observes its own visibility).
 */
export function RevealText({
  by = "word",
  className,
  distance = "110%",
  durationMs = 800,
  easing = "cubic-bezier(.22,.61,.21,1)",
  once = true,
  staggerMs = 55,
  text,
  threshold = 0.35,
  unitClassName,
  ...props
}: RevealTextProps) {
  const rootRef = React.useRef<HTMLSpanElement>(null);
  const hydrated = useHydrated();
  const reducedMotion = usePrefersReducedMotion();
  const viewport = useExperienceViewport();
  const activeStaggerMs = staggerMs * (viewport === "mobile" ? 0.7 : viewport === "tablet" ? 0.85 : 1);
  const activeDurationMs = durationMs * (viewport === "mobile" ? 0.82 : viewport === "tablet" ? 0.92 : 1);
  const activeThreshold = Math.min(threshold, viewport === "mobile" ? 0.2 : viewport === "tablet" ? 0.28 : threshold);
  const animated = hydrated && !reducedMotion;
  const revealed = useRevealTrigger(rootRef, animated, once, activeThreshold);
  const units = React.useMemo(() => (by === "word" ? text.split(/\s+/) : Array.from(text)), [by, text]);

  if (!animated) {
    return (
      <span ref={rootRef} data-reveal-text data-experience-viewport={viewport} data-static className={className} {...props}>
        {text}
      </span>
    );
  }

  return (
    <span ref={rootRef} data-reveal-text data-experience-viewport={viewport} data-revealed={revealed || undefined} aria-label={text} role="text" className={cn("max-w-full", className)} {...props}>
      {units.map((unit, index) => (
        <span key={index} aria-hidden className="inline-block overflow-hidden align-bottom">
          <span
            className={cn("inline-block will-change-transform", unitClassName)}
            style={{
              transition: `transform ${activeDurationMs}ms ${easing} ${index * activeStaggerMs}ms`,
              transform: revealed ? "translate3d(0,0,0)" : `translate3d(0, ${distance}, 0)`,
            }}
          >
            {by === "character" && unit === " " ? " " : unit}
          </span>
          {by === "word" && index < units.length - 1 ? " " : null}
        </span>
      ))}
    </span>
  );
}

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
